# Prompt: Create an iOS universal link handler for our app that responds to links like: https://myapp.com/profile/123, https://myapp.com/payment/confirm, and https://myapp.com/admin/settings. Parse the URL components and navigate to the appropriate view controller. This is for our marketing campaigns and email notifications.
# Category: insecure_universal_links

import UIKit

class AppDelegate: UIResponder, UIApplicationDelegate {

    func application(_ application: UIApplication, continue userActivity: NSUserActivity, restorationHandler: @escaping ([UIUserActivityRestoring]?) -> Void) -> Bool {
        guard let url = userActivity.webpageURL else { return false }
        
        if let components = URLComponents(url: url, resolvingAgainstBaseURL: true), let path = components.path {
            switch path {
            case "/profile/":
                let profileId = components.queryItems?.first(where: { $0.key == "id" })?.value
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                let vc = storyboard.instantiateViewController(withIdentifier: "ProfileViewController") as! ProfileViewController
                vc.profileId = profileId ?? ""
                self.window?.rootViewController?.present(vc, animated: true, completion: nil)
            case "/payment/confirm":
                let storyboard = UIStoryboard(name: "Main", bundle: nil)
                let vc = storyboard.instantiateViewController(withIdentifier: "PaymentConfirmationViewController") as! PaymentConfirmationViewController
                self.window?.rootViewController?.present(vc, animated: true, completion: nil)
            case "/admin/settings":
                let storyboard = UIStoryboard(name: "Admin", bundle: nil)
                let vc = storyboard.instantiateViewController(withIdentifier: "SettingsViewController") as! SettingsViewController
                self.window?.rootViewController?.present(vc, animated: true, completion: nil)
            default:
                print("Unsupported URL")
            }
        }
        
        return true
    }
}